export type BrokerNotificationMethod = keyof BrokerNotificationParamsRawByMethod;
export type RemoteMethod = RemoteRequestMethod | RemoteNotificationMethod | BrokerRequestMethod | BrokerNotificationMethod;
export type RemoteRequestParamsRaw<M extends RemoteRequestMethod> = RemoteRequestParamsRawByMethod[M];
export type RemoteRequestParamsHydrated<M extends RemoteRequestMethod> = RemoteRequestParamsHydratedByMethod[M];
export type RemoteRequestResultRaw<M extends RemoteRequestMethod> = RemoteRequestResultRawByMethod[M];
export type RemoteRequestResultHydrated<M extends RemoteRequestMethod> = RemoteRequestResultHydratedByMethod[M];
export type RemoteNotificationParamsRaw<M extends RemoteNotificationMethod> = RemoteNotificationParamsRawByMethod[M];
export type RemoteNotificationParamsHydrated<M extends RemoteNotificationMethod> = RemoteNotificationParamsHydratedByMethod[M];
